# scripts/audit_seeds.py
import ast
import sys
from pathlib import Path

RANDOM_SEED = 42

SEED_REQUIRED_CLASSES = {
    "LogisticRegression",
    "RandomForestClassifier",
    "GradientBoostingClassifier",
    "XGBClassifier",
    "KFold",
    "StratifiedKFold",
    "RandomizedSearchCV",
    "GridSearchCV",
    "SMOTE",
    "train_test_split",  # should be absent, but flag if found
}

SEED_FORBIDDEN = {"train_test_split"}  # should not appear in evaluation code


def audit_file(path: Path) -> list[str]:
    issues = []
    try:
        tree = ast.parse(path.read_text())
    except SyntaxError:
        return [f"{path}: SyntaxError — could not parse"]

    for node in ast.walk(tree):
        if not isinstance(node, ast.Call):
            continue

        func_name = ""
        if isinstance(node.func, ast.Name):
            func_name = node.func.id
        elif isinstance(node.func, ast.Attribute):
            func_name = node.func.attr

        if func_name in SEED_FORBIDDEN:
            issues.append(f"{path}:{node.lineno} — FORBIDDEN: {func_name} used (should use K-Fold CV)")
            continue

        if func_name in SEED_REQUIRED_CLASSES:
            kwarg_names = {kw.keyword if isinstance(kw, ast.keyword) else kw.arg for kw in node.keywords}
            # ast.keyword has .arg, not .keyword
            kwarg_names = {kw.arg for kw in node.keywords if hasattr(kw, "arg")}
            if "random_state" not in kwarg_names:
                issues.append(f"{path}:{node.lineno} — MISSING random_state in {func_name}()")

    return issues


def main():
    root = Path("churn_model")
    all_issues = []
    for py_file in root.rglob("*.py"):
        all_issues.extend(audit_file(py_file))

    if all_issues:
        print("Seed audit FAILED:")
        for issue in all_issues:
            print(f"  {issue}")
        sys.exit(1)
    else:
        print(f"Seed audit PASSED — random_state=42 present everywhere it should be.")


if __name__ == "__main__":
    main()
